    fn test_cyclic_graph() {
        let graph = vec![(1, 2), (2, 3), (3, 4), (4, 5), (4, 2)];
        let sort = topological_sort(&graph);
        assert!(sort.is_err());
        assert_eq!(sort.err().unwrap(), TopoligicalSortError::CycleDetected);
