 *
 * This sorting algorithm randomly rearranges the array until it is sorted.
 *
 * For more information see: https://en.wikipedia.org/wiki/Bogosort
 */
export function bogoSort(items) {
  while (!isSorted(items)) {
    shuffle(items)
  }
  return items
}

